template <typename F, int N>
static double benchmark(F&& f) {
    double best = DBL_MAX;
    for (int i = 0; i < N; i++) {
        double v = f();
        if (v < best) best = v;
    }
    return best;
}

static void flushed_printf(const char* format, ...) {
    va_list args;
    va_start(args, format);
    vprintf(format, args);
    va_end(args);
    fflush(stdout);
}

static void show_progress_init(int length) {
    flushed_printf("[");
    for (int i = 0; i < length; i++) flushed_printf(" ");
    flushed_printf("]");
    for (int i = 0; i <= length; i++) flushed_printf("\b");
}

static void show_progress_step(int domove, char newchar) {
    flushed_printf("%c", newchar);
    if (!domove) flushed_printf("\b");
}

static void show_progress_done(void) { flushed_printf("\n"); }

template <typename T>
struct TypeOps;

template <>
struct TypeOps<float> {
    __device__ __forceinline__ static float zero() { return 0.0f; }
    __device__ __forceinline__ static float minus_one() { return -1.0f; }
    __device__ __forceinline__ static float add(float a, float b) { return a + b; }
    __device__ __forceinline__ static float mul(float a, float b) { return a * b; }
    __device__ __forceinline__ static float mad(float a, float seed) { return a * a + seed; }
    __device__ __forceinline__ static bool equal(float a, float b) { return a == b; }
};

template <>
struct TypeOps<double> {
    __device__ __forceinline__ static double zero() { return 0.0; }
    __device__ __forceinline__ static double minus_one() { return -1.0; }
    __device__ __forceinline__ static double add(double a, double b) { return a + b; }
    __device__ __forceinline__ static double mul(double a, double b) { return a * b; }
    __device__ __forceinline__ static double mad(double a, double seed) { return a * a + seed; }
    __device__ __forceinline__ static bool equal(double a, double b) { return a == b; }
};

template <>
struct TypeOps<int> {
    __device__ __forceinline__ static int zero() { return 0; }
    __device__ __forceinline__ static int minus_one() { return -1; }
    __device__ __forceinline__ static int add(int a, int b) {
        return static_cast<int>(static_cast<uint32_t>(a) + static_cast<uint32_t>(b));
    }
    __device__ __forceinline__ static int mul(int a, int b) {
        return static_cast<int>(static_cast<uint32_t>(a) * static_cast<uint32_t>(b));
    }
    __device__ __forceinline__ static int mad(int a, int seed) {
        return add(mul(a, a), seed);
    }
    __device__ __forceinline__ static bool equal(int a, int b) { return a == b; }
};

template <>
struct TypeOps<short> {
    __device__ __forceinline__ static short zero() { return 0; }
    __device__ __forceinline__ static short minus_one() { return static_cast<short>(-1); }
    __device__ __forceinline__ static short add(short a, short b) {
        return static_cast<short>(static_cast<uint16_t>(a) + static_cast<uint16_t>(b));
    }
    __device__ __forceinline__ static short mul(short a, short b) {
        return static_cast<short>(static_cast<uint16_t>(a) * static_cast<uint16_t>(b));
    }
    __device__ __forceinline__ static short mad(short a, short seed) {
        return add(mul(a, a), seed);
    }
    __device__ __forceinline__ static bool equal(short a, short b) { return a == b; }
};

template <>
struct TypeOps<__half2> {
    __device__ __forceinline__ static __half2 zero() { return __float2half2_rn(0.0f); }
    __device__ __forceinline__ static __half2 minus_one() { return __float2half2_rn(-1.0f); }
    __device__ __forceinline__ static __half2 add(__half2 a, __half2 b) { return __hadd2(a, b); }
    __device__ __forceinline__ static __half2 mul(__half2 a, __half2 b) { return __hmul2(a, b); }
    __device__ __forceinline__ static __half2 mad(__half2 a, __half2 seed) {
        return __hadd2(__hmul2(a, a), seed);
    }
    __device__ __forceinline__ static bool equal(__half2 a, __half2 b) {
        __half al = __low2half(a);
        __half ah = __high2half(a);
        __half bl = __low2half(b);
        __half bh = __high2half(b);
        return al.x == bl.x && ah.x == bh.x;
    }
};

template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_func(T seed, T* g_data, long size) {
    const unsigned int blockSize = blockDim.x;
    const long num_groups = gridDim.x;

    int stride;
    long idx;
    if (BLOCK_STRIDED) {
        stride = static_cast<int>(blockSize);
        idx = static_cast<long>(blockIdx.x) * blockSize * ELEMENTS_PER_THREAD + threadIdx.x;
    } else {
        const int grid_size = static_cast<int>(blockSize * num_groups);
        stride = grid_size;
        idx = static_cast<long>(blockIdx.x) * blockSize + threadIdx.x;
    }
    const long big_stride = num_groups * blockSize * ELEMENTS_PER_THREAD;

    T tmps[ELEMENTS_PER_THREAD];
#pragma unroll
    for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            const long pos = idx + static_cast<long>(j) * stride + static_cast<long>(k) * big_stride;
            tmps[j] = (pos < size) ? g_data[pos] : TypeOps<T>::zero();
#pragma unroll
            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = TypeOps<T>::mad(tmps[j], seed);
            }
        }

        T sum = TypeOps<T>::zero();
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
            sum = TypeOps<T>::add(sum, TypeOps<T>::mul(tmps[j], tmps[j + 1]));
        }

        if (TypeOps<T>::equal(sum, TypeOps<T>::minus_one())) {
            const long out_pos = idx + static_cast<long>(k) * big_stride;
            if (out_pos < size) g_data[out_pos] = sum;
        }
    }
}

using KernelLauncher = void (*)(void*, long, size_t, size_t, cudaStream_t);

template <int CI>
static void launch_float_kernel(void* buf, long size, size_t blocks, size_t wg, cudaStream_t stream) {
    benchmark_func<float, CI, kElementsPerWI, kFusionDegree, kBlockStrided>
        <<<static_cast<unsigned int>(blocks), static_cast<unsigned int>(wg), 0, stream>>>(
            1.0f, reinterpret_cast<float*>(buf), size);
}

template <int CI>
static void launch_double_kernel(void* buf, long size, size_t blocks, size_t wg, cudaStream_t stream) {
    benchmark_func<double, CI, kElementsPerWI, kFusionDegree, kBlockStrided>
        <<<static_cast<unsigned int>(blocks), static_cast<unsigned int>(wg), 0, stream>>>(
            1.0, reinterpret_cast<double*>(buf), size);
}

template <int CI>
static void launch_int_kernel(void* buf, long size, size_t blocks, size_t wg, cudaStream_t stream) {
    benchmark_func<int, CI, kElementsPerWI, kFusionDegree, kBlockStrided>
        <<<static_cast<unsigned int>(blocks), static_cast<unsigned int>(wg), 0, stream>>>(
            1, reinterpret_cast<int*>(buf), size);
}

template <int CI>
static void launch_half_kernel(void* buf, long size, size_t blocks, size_t wg, cudaStream_t stream) {
    const __half2 seed = __float2half2_rn(1.0f);
    benchmark_func<__half2, CI, kElementsPerWI, kFusionDegree, kBlockStrided>
        <<<static_cast<unsigned int>(blocks), static_cast<unsigned int>(wg), 0, stream>>>(
            seed, reinterpret_cast<__half2*>(buf), size);
}

