static void runbench_warmup(cudaStream_t stream, void* cbuffer, long size, size_t workgroupsize) {
    const long reduced_grid_size = size / 256;
    const size_t blocks = static_cast<size_t>(reduced_grid_size) / workgroupsize;
    benchmark_func<short, 0, 1, 1, kBlockStrided>
        <<<static_cast<unsigned int>(blocks), static_cast<unsigned int>(workgroupsize), 0, stream>>>(
            static_cast<short>(1), reinterpret_cast<short*>(cbuffer), size);
    CUDA_SAFE_CALL(cudaGetLastError());
}

static double time_launcher(KernelLauncher launcher,
                            void* buffer,
                            long size,
                            size_t blocks,
                            size_t workgroupsize,
                            cudaStream_t stream,
                            bool use_os_timer) {
    if (use_os_timer) {
        auto ts_start = std::chrono::high_resolution_clock::now();
        launcher(buffer, size, blocks, workgroupsize, stream);
        CUDA_SAFE_CALL(cudaGetLastError());
        CUDA_SAFE_CALL(cudaStreamSynchronize(stream));
        auto ts_end = std::chrono::high_resolution_clock::now();
        return std::chrono::duration<double, std::milli>(ts_end - ts_start).count();
    } else {
        cudaEvent_t ev_start, ev_stop;
        CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
        CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
        CUDA_SAFE_CALL(cudaEventRecord(ev_start, stream));
        launcher(buffer, size, blocks, workgroupsize, stream);
        CUDA_SAFE_CALL(cudaGetLastError());
        CUDA_SAFE_CALL(cudaEventRecord(ev_stop, stream));
        CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
        float ms = 0.0f;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
        return static_cast<double>(ms);
    }
}

static void runbench(const int compute_iterations[],
                     unsigned int krn_idx,
                     cudaStream_t stream,
                     void* cbuffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool use_os_timer,
                     bool enable_dp,
                     bool enable_hp) {
    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const int current_compute_iterations = compute_iterations[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;
    const size_t blocks = (size_t)compute_grid_size / workgroupsize;

    constexpr int total_bench_iterations = 3;

    double kernel_time_mad_sp = benchmark<decltype([&]{}), total_bench_iterations>([&]() {
        return time_launcher(float_launchers[krn_idx], cbuffer, size, blocks, workgroupsize, stream,
                             use_os_timer);
    });

    double kernel_time_mad_dp = benchmark<decltype([&]{}), total_bench_iterations>([&]() {
        if (enable_dp)
            return time_launcher(double_launchers[krn_idx], cbuffer, size, blocks, workgroupsize,
                                 stream, use_os_timer);
        return 0.0;
    });

    double kernel_time_mad_hp = benchmark<decltype([&]{}), total_bench_iterations>([&]() {
        if (enable_hp)
            return time_launcher(half_launchers[krn_idx], cbuffer, size, blocks, workgroupsize,
                                 stream, use_os_timer);
        return 0.0;
    });

    double kernel_time_mad_int = benchmark<decltype([&]{}), total_bench_iterations>([&]() {
        return time_launcher(int_launchers[krn_idx], cbuffer, size, blocks, workgroupsize, stream,
                             use_os_timer);
    });

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp,
        ((double)computations) / kernel_time_mad_dp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp,
        ((double)2 * computations) / kernel_time_mad_hp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
            (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
    printf("Workgroup size:         %d\n", (int)kWorkgroupSize);
    printf("Elements per workitem:  %d\n", kElementsPerWI);
    printf("Workitem fusion degree: %d\n", kFusionDegree);

    const char* benchtype = kBlockStrided ? "Workgroup" : "NDRange";
    printf("Workitem stride:        %s\n", benchtype);
    const char* buffer_allocation = kHostAllocated ? "Host allocated" : "Device allocated";
    printf("Buffer allocation:      %s\n", buffer_allocation);
    printf("Timer:                  %s\n", kUseOSTimer ? "OS based" : "CL event based");

    cudaDeviceProp prop = GetDeviceProperties();
    bool enable_dp = (prop.major > 1) || (prop.major == 1 && prop.minor >= 3);
    if (!enable_dp)
        printf("Warning:                Double precision computations are not supported\n");
    bool enable_hp = IsFP16Supported();
    if (!enable_hp)
        printf("Warning:                Half precision computations are not supported\n");

    void* c_buffer = nullptr;
    CUDA_SAFE_CALL(cudaMalloc(&c_buffer, size * sizeof(double)));

    cudaStream_t stream;
    CUDA_SAFE_CALL(cudaStreamCreate(&stream));

    CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, size * sizeof(int)));

    printf("Loading kernel source file...\n");
    printf("Precompilation of kernels... ");
    show_progress_init(compute_iterations_len);
    for (int i = 0; i < compute_iterations_len; i++) {
        show_progress_step(0, '\\');
        show_progress_step(0, '|');
        if (enable_dp) show_progress_step(0, '/');
        if (enable_hp) show_progress_step(0, '-');
        show_progress_step(1, '>');
    }
    show_progress_done();

    runbench_warmup(stream, c_buffer, size, kWorkgroupSize);
    CUDA_SAFE_CALL(cudaStreamSynchronize(stream));

    printf(
        "----------------------------------------------------------------------------- CSV data "
        "-----------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++) {
        runbench(compute_iterations, i, stream, c_buffer, size, kWorkgroupSize, kElementsPerWI,
                 kFusionDegree, kUseOSTimer, enable_dp, enable_hp);
    }

    printf(
        "------------------------------------------------------------------------"
        "------------------------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, size * sizeof(double), cudaMemcpyDeviceToHost));

    CUDA_SAFE_CALL(cudaStreamDestroy(stream));
    CUDA_SAFE_CALL(cudaFree(c_buffer));
}
